323	// TestProviderConnectivityViaService runs a HealthCheck against the named
324	// harness and translates the result into a ProviderStatus. It is the
325	// production replacement for Runner.TestProviderConnectivity.
326	func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
327		status := ProviderStatus{Reachable: false}
328		if ctx == nil {
329			ctx = context.Background()
330		}
331		if harnessName == "virtual" || harnessName == "agent" {
332			status.Reachable = true
333			status.CreditsOK = true
334			return status
335		}
336		svc, err := NewServiceFromWorkDir(workDir)
337		if err != nil {
338			status.Error = err.Error()
339			return status
340		}
341		if timeout > 0 {
342			var cancel context.CancelFunc
343			ctx, cancel = context.WithTimeout(ctx, timeout)
344			defer cancel()
345		}
346		if err := svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: harnessName}); err != nil {
347			errStr := strings.ToLower(err.Error())
348			status.Error = err.Error()
349			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
350				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
351				status.CreditsOK = false
352			}
353			return status
354		}
355		status.Reachable = true
356		status.CreditsOK = true
357		return status
358	}
