360	// ValidateForExecuteLoopViaService is the production replacement for
361	// Runner.ValidateForExecuteLoop. When harness is empty it is a no-op (routing
362	// will pick at claim time). When harness is specified it confirms the harness
363	// exists in the service registry and (when model is set) attempts a
364	// ResolveRoute pre-flight.
365	func ValidateForExecuteLoopViaService(ctx context.Context, workDir, harnessName, model, provider, modelRef string) error {
366		if harnessName == "" {
367			return nil
368		}
369		if ctx == nil {
370			ctx = context.Background()
371		}
372		svc, err := NewServiceFromWorkDir(workDir)
373		if err != nil {
374			return fmt.Errorf("agent: build service: %w", err)
375		}
376		infos, err := svc.ListHarnesses(ctx)
377		if err != nil {
378			return fmt.Errorf("agent: list harnesses: %w", err)
379		}
380		found := false
381		for _, info := range infos {
382			if info.Name == harnessName {
383				found = true
384				if !info.Available {
385					return fmt.Errorf("agent: harness %s not available", harnessName)
386				}
387				break
388			}
389		}
390		if !found {
391			return fmt.Errorf("agent: unknown harness: %s", harnessName)
392		}
393	
394		// Pre-flight orphan-model check via ResolveRoute. Only meaningful when a
395		// model is provided and provider/model-ref are not set.
396		if model != "" && provider == "" && modelRef == "" && harnessName == "agent" {
397			if _, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{
398				Model:    model,
399				Harness:  harnessName,
400				ModelRef: modelRef,
401				Provider: provider,
402			}); err != nil {
403				return fmt.Errorf("agent: model %q is not routable: %w", model, err)
404			}
405		}
406		return nil
407	}
